CREATE TABLE `news` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `content` text NOT NULL,
  `image` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `news` (`title`, `content`, `image`, `created_at`) VALUES
('День открытых дверей в Учебном центре', '15 апреля 2026 года приглашаем всех желающих на День открытых дверей! В программе: экскурсия по производственным цехам АО «НПО «Курганприбор», мастер-классы от опытных наставников, консультации по вопросам поступления на программы профессиональной подготовки и переподготовки. Начало в 14:00.', 'news_openhouse.jpg', '2026-03-20 08:00:00'),
('Успешная защита квалификационных работ', '25 марта 2026 года в Учебном центре состоялась итоговая аттестация слушателей программы «Оператор станков с программным управлением». Все 12 выпускников успешно справились с практическими заданиями и получили свидетельства установленного образца. Лучшие выпускники приглашены на работу в механический цех предприятия.', 'news_graduates.jpg', '2026-03-26 16:30:00'),
('Новое оборудование в учебных лабораториях', 'Учебный центр получил 3 новых современных токарных станка с ЧПУ HAAS ST-10Y и 5 комплектов контрольно-измерительного оборудования. Теперь слушатели смогут осваивать передовые методы обработки металлов и контроля качества на самом современном оборудовании.', 'news_equipment.jpg', '2026-02-28 10:15:00');

