CREATE TABLE `programs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `duration` varchar(100) NOT NULL,
  `requirements` text NOT NULL,
  `curriculum` text NOT NULL,
  `description` text NOT NULL,
  `image` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `programs` (`title`, `duration`, `requirements`, `curriculum`, `description`, `image`) VALUES
('Оператор станков с программным управлением (2-й разряд)', '199 часов', 'Среднее общее образование и профессиональное обучение - программы профессиональной подготовки/переподготовки. Обязательное прохождение медицинского осмотра и инструктажа по охране труда.', 'Учебный план включает: материаловедение (3 ч), техническое черчение (3 ч), охрана труда (3 ч), допуски и технические измерения (15 ч), технология машиностроения (6 ч), технология металлообработки на станках с ЧПУ (9 ч), производственное обучение (154 ч), итоговая аттестация (6 ч).', 'Программа направлена на подготовку квалифицированных операторов для работы на токарных и фрезерных станках с числовым программным управлением. Слушатели осваивают чтение чертежей, настройку оборудования, управляющих программ и контроль качества изготовления простых деталей типа тел вращения. Разработана на основе профстандарта "Оператор металлорежущих станков с ЧПУ".', 'operator_cnc.jpg'),
('Контролер станочных и слесарных работ (3-й разряд)', '72 часа', 'Среднее профессиональное образование. Наличие профессии рабочего для программ переподготовки или без требований к наличию профессии для программ подготовки.', 'Учебный план включает: материаловедение (2 ч), основы технической графики (10 ч), процессы формообразования (6 ч), допуски и технические измерения (36 ч), технология машиностроения (12 ч), итоговая аттестация (6 ч).', 'Программа предназначена для специалистов по техническому контролю качества в механосборочном производстве. Слушатели учатся контролировать детали средней сложности, читать конструкторскую документацию, использовать универсальные измерительные инструменты (штангенциркули, микрометры, калибры), а также анализировать виды и причины брака. Соответствует профстандарту "Контролер станочных и слесарных работ".', 'controller.jpg'),
('Наладчик станков с ЧПУ (5-й разряд)', '320 часов', 'Среднее профессиональное образование. Наличие квалификации «Оператор станков с ЧПУ» или опыт работы не менее 1 года.', 'Учебный план: материаловедение и термическая обработка (24 ч), программирование управляющих систем (48 ч), наладка и настройка станков (64 ч), сложные виды фрезерной и токарной обработки (48 ч), диагностика и ремонт оборудования (32 ч), учебная практика (96 ч), итоговая аттестация (8 ч).', 'Программа повышения квалификации для опытных операторов, желающих освоить профессию наладчика. Слушатели изучают сложные методы программирования, настройку многоосевых станков, подбор режимов резания и оптимизацию технологических процессов. По окончании выдается удостоверение установленного образца с присвоением 5-го разряда.', 'setup_cnc.jpg'),
('Слесарь механосборочных работ (3-й разряд)', '160 часов', 'Среднее общее образование. Без предъявления требований к опыту работы.', 'Учебный план: слесарное дело и основы механики (24 ч), чтение сборочных чертежей (16 ч), виды разъемных и неразъемных соединений (20 ч), сборка узлов и механизмов (32 ч), контроль и испытания сборочных единиц (16 ч), производственная практика (48 ч), итоговая аттестация (4 ч).', 'Программа профессиональной подготовки для получения востребованной рабочей профессии. Слушатели осваивают слесарные операции (разметка, рубка, опиливание, сверление), сборку механизмов, регулировку узлов и контроль качества сборки. Обучение проходит как в учебных мастерских, так и непосредственно на рабочих местах в сборочных цехах предприятия.', 'fitter.jpg');

